			.where({ _id: id })
			.update({
				access_token: accessToken,
				refresh_token: refreshToken,
				token_expires_at: tokenExpiresAt,
				updated_at: this.knexWrite.fn.now(),
			});
	} catch (error) {
		this.logger.error(`Failed to update tokens for ${id}: ${(error as Error).message}`);
		throw error;
	}
}

